:root {
  --color-primary-black: #000000;
  --color-primary-red: #D23A25;
  --color-secondary-orange: #F26922;
  --color-secondary-gold: #F6B13A;
  --color-accent-white: #FFFFFF;
  --color-neutral-900: #1A1A1A;
  --color-neutral-700: #444444;
  --color-neutral-500: #777777;
  --color-neutral-300: #CCCCCC;
  --color-paper-light: #F5F5F5;

  --font-heading: "Playfair Display", Georgia, serif;
  --font-body: "Libre Franklin", Helvetica, Arial, sans-serif;
  --font-code: "Source Code Pro", monospace;

  --font-size-h1: 40px;
  --font-size-h2: 32px;
  --font-size-h3: 24px;
  --font-size-body: 14px;
  --font-size-small: 12px;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  --space-0-5: 4px;
  --space-1: 8px;
  --space-2: 16px;
  --space-3: 24px;
  --space-4: 32px;
  --space-5: 48px;
  --space-6: 64px;

  --border-radius-none: 0;
  --border-radius-xs: 2px;
  --border-thin: 1px;
  --border-thick: 4px;

  --max-content-width: 1040px;
}

/* Basic reset */
*,
*::before,
*::after {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body.site-body {
  min-height: 100vh;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-accent-white);
  background-color: var(--color-paper-light);
}

.page-background {
  min-height: 100vh;
  background-image:
    radial-gradient(circle at 0 0, #ffffff 0, #e8e8e8 40%, #f5f5f5 70%),
    radial-gradient(circle at 100% 0, #ffffff 0, #eaeaea 40%, #f5f5f5 70%),
    radial-gradient(circle at 0 100%, #ffffff 0, #e7e7e7 40%, #f5f5f5 70%),
    radial-gradient(circle at 100% 100%, #ffffff 0, #e9e9e9 40%, #f5f5f5 70%);
  background-blend-mode: multiply;
}

.site-header {
  background-color: var(--color-primary-black);
  color: var(--color-accent-white);
  border-bottom: var(--border-thin) solid #111111;
}

.header-inner {
  max-width: var(--max-content-width);
  margin: 0 auto;
  padding: var(--space-3) var(--space-2) var(--space-2);
  text-align: center;
}

.brand-block {
  margin-bottom: var(--space-2);
}

.site-tagline {
  margin: 0 0 var(--space-0-5);
  font-family: var(--font-body);
  font-size: var(--font-size-small);
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: var(--color-neutral-300);
}

.site-title {
  display: inline-block;
  margin: 0;
  font-family: var(--font-heading);
  font-size: 34px;
  font-weight: 600;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  text-decoration: none;
  color: #b3b3b3;
}

.site-title:hover,
.site-title:focus {
  color: var(--color-accent-white);
}

.primary-nav {
  border-top: var(--border-thin) solid #111111;
  padding-top: var(--space-1);
}

.primary-nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  justify-content: center;
  gap: 40px;
}

.primary-nav-item {
  margin: 0;
}

.primary-nav-link {
  position: relative;
  display: inline-block;
  padding: var(--space-0-5) 0;
  font-family: var(--font-body);
  font-size: 13px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  text-decoration: none;
  color: var(--color-accent-white);
  transition: color 0.2s ease;
}

.primary-nav-link:hover,
.primary-nav-link:focus {
  color: var(--color-primary-red);
}

.nav-link--active {
  color: var(--color-primary-red);
}

.site-main {
  padding: var(--space-5) var(--space-2) var(--space-5);
}

.content-frame {
  max-width: var(--max-content-width);
  margin: 0 auto;
  padding: var(--space-4);
  background-color: #050505;
  border: var(--border-thick) solid var(--color-primary-black);
  box-shadow: 0 0 0 1px #222222 inset;
  color: var(--color-accent-white);
}

/* Typography helpers */

h1,
.h1 {
  font-family: var(--font-heading);
  font-size: var(--font-size-h1);
  line-height: var(--line-height-tight);
}

h2,
.h2 {
  font-family: var(--font-heading);
  font-size: var(--font-size-h2);
  line-height: var(--line-height-tight);
}

h3,
.h3 {
  font-family: var(--font-heading);
  font-size: var(--font-size-h3);
  line-height: var(--line-height-tight);
}

p {
  margin-top: 0;
  margin-bottom: var(--space-1);
}

/* Card pattern (portrait, subscription-like panels) */

.card-frame {
  border: var(--border-thick) solid var(--color-primary-black);
  padding: var(--space-1);
  background-color: #0b0b0b;
}

.card-frame-inner {
  border: var(--border-thin) solid var(--color-accent-white);
  padding: var(--space-2);
}

.card-panel {
  background-color: var(--color-neutral-900);
  border: var(--border-thin) solid var(--color-neutral-700);
  padding: var(--space-2);
}

.card-panel--header-strip {
  padding: var(--space-1) var(--space-2);
  border-bottom: var(--border-thin) solid #666666;
  background-color: #3a3a3a;
  font-size: var(--font-size-small);
}

/* Form pattern */

.form-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: var(--space-1);
}

.form-grid--stacked {
  grid-template-columns: 1fr;
}

.form-field,
.form-textarea {
  width: 100%;
  border-radius: var(--border-radius-none);
  border: var(--border-thin) solid #666666;
  background-color: #444444;
  color: var(--color-accent-white);
  padding: 6px 8px;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
}

.form-field::placeholder,
.form-textarea::placeholder {
  color: #aaaaaa;
}

.form-textarea {
  min-height: 160px;
  resize: vertical;
}

/* Buttons */

.btn {
  display: inline-block;
  padding: 10px 18px;
  border-radius: var(--border-radius-xs);
  border: none;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  text-transform: uppercase;
  letter-spacing: 0.12em;
  text-align: center;
  cursor: pointer;
}

.btn-primary {
  width: 100%;
  background-color: var(--color-secondary-orange);
  color: var(--color-primary-black);
  border: 1px solid var(--color-secondary-gold);
}

.btn-primary:hover,
.btn-primary:focus {
  background-color: #ff7b32;
}

.btn-secondary {
  background-color: var(--color-neutral-900);
  color: var(--color-accent-white);
  border: 1px solid #666666;
}

.btn-secondary:hover,
.btn-secondary:focus {
  background-color: #262626;
}

/* Footer */

.site-footer {
  background-color: var(--color-primary-black);
  color: var(--color-neutral-300);
  border-top: 2px solid var(--color-primary-red);
}

.footer-inner {
  max-width: var(--max-content-width);
  margin: 0 auto;
  padding: var(--space-4) var(--space-2) var(--space-3);
}

.footer-branding {
  text-align: center;
  margin-bottom: var(--space-3);
}

.footer-title {
  margin: 0 0 var(--space-0-5);
  font-family: var(--font-heading);
  font-size: 22px;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: #b3b3b3;
}

.footer-tagline {
  margin: 0;
  font-size: var(--font-size-small);
  letter-spacing: 0.12em;
  text-transform: uppercase;
}

.footer-nav {
  border-top: 1px solid #111111;
  border-bottom: 1px solid #111111;
  padding: var(--space-2) 0;
}

.footer-nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(120px, 1fr));
  gap: var(--space-1) var(--space-3);
  text-align: center;
}

.footer-nav-link {
  font-family: var(--font-body);
  font-size: var(--font-size-small);
  text-transform: uppercase;
  letter-spacing: 0.14em;
  text-decoration: none;
  color: var(--color-neutral-300);
  transition: color 0.2s ease;
}

.footer-nav-link:hover,
.footer-nav-link:focus {
  color: var(--color-primary-red);
}

.footer-meta {
  margin: var(--space-2) 0 0;
  text-align: center;
  font-size: var(--font-size-small);
  color: var(--color-neutral-500);
}

/* Responsive adjustments */

@media (max-width: 768px) {
  .header-inner {
    padding: var(--space-2) var(--space-2) var(--space-1);
  }

  .primary-nav-list {
    flex-wrap: wrap;
    gap: 20px;
  }

  .content-frame {
    padding: var(--space-3);
  }

  .site-main {
    padding: var(--space-4) var(--space-1) var(--space-4);
  }
}
